// 1. string: Text values
let userName: string = "Murad"; // Only string
// userName = 23; // Error: number is not string type

// 2. number: Integer or decimal numbers
let userAge: number = 23; // Only number
// userAge = "twenty three"; // Error: string is not number type

// 3. boolean: True or False
let isActive: boolean = true; // Only true/false
// isActive = "yes"; // Error: string is not boolean type

// 4. any: Any type
let data: any = "test"; // Can be string
data = 42; // Can be number
data = true; // Accepts any value

// 5. array: List of same-type values
let prices: number[] = [10, 20, 30]; // Only numbers
// prices.push("40"); // Error: string is not number[] type

// 6. tuple: Fixed-length array
type UserInfo = [string, number];
let user: UserInfo = ["Alice", 25]; // Name and age
// user = [25, "Alice"]; // Error: types are in wrong order

// 7. void: Function returning no value
function logMessage(message: string): void {
  console.log(message); // Returns nothing
}

// 8. null and undefined
let emptyValue: null = null; // Only null
let notDefined: undefined = undefined; // Only undefined

// Simple store system
let productName: string = "Laptop"; // Product name
let productPrice: number = 1200; // Product price
let inStock: boolean = true; // Availability
let productIds: number[] = [101, 102, 103]; // Product IDs

type ProductInfo = [string, number]; // Product name and price
let product: ProductInfo = ["Mouse", 25];

function showProduct(name: string, price: number): string {
  return `${name}: $${price}`;
}

console.log(showProduct(productName, productPrice)); // Output: Laptop: $1200
console.log(showProduct(product[0], product[1])); // Output: Mouse: $25

